import 'package:flutter/material.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class PaymentProcessor {
  final FlutterSecureStorage _storage = const FlutterSecureStorage();

  // iOS-specific integration (Apple Pay, Google Pay)
  Future<void> initAppPayments() async {
    if (kIsWeb) return; // For web version
    await MethodChannel('plugins.flutter.io/in_app_purchase')
        .invokeMethod('initializeInAppPurchase', {});
  }

  Future<void> initiatePayment(Map<String, String> paymentData) async {
    try {
      await _storage.write(key: 'paymentToken', value: paymentData['token']);
      await _storage.write(key: 'customerInfo', value: paymentData['customer']);

      if (kIsWeb || !Platform.isIOS && !Platform.isAndroid) return; // Web or unsupported platforms
      final channel = MethodChannel('plugins.flutter.io/in_app_purchase');
      await channel.invokeMethod('makePurchase', {
        'amount': paymentData['amount'],
        'currencyCode': paymentData['currency'],
        'paymentToken': paymentData['token']
      });
    } catch (e) {
      print('Error making purchase: $e');
    }
  }

  Future<String> getPaymentStatus() async {
    final storage = const FlutterSecureStorage();
    final status = await storage.read(key: 'paymentStatus') ?? '';

    return status;
  }
}

